#!/usr/bin/env python3
"""Fix docker-compose.yml properly."""

with open("/root/se-toolkit-lab-8/docker-compose.yml", "r") as f:
    lines = f.readlines()

result = []
in_nanobot = False
in_flutter = False
in_caddy_depends = False
in_caddy_env = False
in_caddy_vol = False

for i, line in enumerate(lines):
    stripped = line.strip()

    # Nanobot service
    if '  # Task 2A — uncomment and adapt this service' in line:
        result.append('  # Task 2A — nanobot gateway\n')
        in_nanobot = True
        continue
    if in_nanobot:
        if line.startswith('  #   '):
            result.append(line.replace('# ', '', 1))
            continue
        elif line.startswith('  #     '):
            result.append(line.replace('# ', '', 1))
            continue
        elif line.startswith('  #       '):
            result.append(line.replace('# ', '', 1))
            continue
        elif line.startswith('  #   depends_on:'):
            result.append(line.replace('# ', '', 1))
            continue
        elif line.startswith('  #     - backend') or line.startswith('  #     - qwen-code-api'):
            result.append(line.replace('# ', '', 1))
            continue
        elif stripped.startswith('#'):
            in_nanobot = False
        else:
            in_nanobot = False

    # Flutter service
    if '  # Task 2B — uncomment after you add nanobot-websocket-channel' in line:
        result.append('  # Task 2B — Flutter client\n')
        in_flutter = True
        continue
    if in_flutter:
        if line.startswith('  #   '):
            result.append(line.replace('# ', '', 1))
            continue
        elif line.startswith('  #     '):
            result.append(line.replace('# ', '', 1))
            continue
        elif line.startswith('  #       '):
            result.append(line.replace('# ', '', 1))
            continue
        elif stripped.startswith('#') and 'client-web-flutter' not in line:
            in_flutter = False
        else:
            in_flutter = False

    # Caddy depends_on
    if 'depends_on:' in line and 'caddy' in ''.join(lines[max(0,i-10):i]):
        in_caddy_depends = True
        result.append(line)
        continue
    if in_caddy_depends:
        if '# - client-web-flutter' in line:
            result.append(line.replace('# ', '', 1))
            continue
        if '# - nanobot' in line:
            result.append(line.replace('# ', '', 1))
            continue
        if not stripped.startswith('#') and stripped:
            in_caddy_depends = False
        result.append(line)
        continue

    # Caddy environment
    if 'environment:' in line and 'caddy' in ''.join(lines[max(0,i-10):i]):
        in_caddy_env = True
        result.append(line)
        continue
    if in_caddy_env:
        if '# - NANOBOT_WEBCHAT' in line:
            result.append(line.replace('# ', '', 1))
            continue
        if not stripped.startswith('#') and stripped:
            in_caddy_env = False
        result.append(line)
        continue

    # Caddy volumes
    if 'volumes:' in line and 'caddy' in ''.join(lines[max(0,i-10):i]):
        in_caddy_vol = True
        result.append(line)
        continue
    if in_caddy_vol:
        if '# - client-web-flutter:/srv/flutter' in line:
            result.append(line.replace('# ', '', 1))
            continue
        if not stripped.startswith('#') and stripped:
            in_caddy_vol = False
        result.append(line)
        continue

    result.append(line)

with open("/root/se-toolkit-lab-8/docker-compose.yml", "w") as f:
    f.writelines(result)

print("docker-compose.yml fixed")

